const body = $input.first().json;

const userName = body.data?.user_name || 'Artist';
const userEmail = body.data?.user_email;
const eventType = body.event_type || '';

if (!userEmail) {
  throw new Error('No user_email in event data');
}

let emailSubject, emailBody;

if (eventType === 'streak.achieved') {
  const streakLength = body.data?.streak_length || 0;
  const achievementLevel = body.data?.achievement_level || 'bronze';
  const celebrationType = body.data?.celebration_type || 'badge';

  emailSubject = `🔥 ${streakLength}-day streak! You're on fire, ${userName}!`;
  emailBody = `Hi ${userName},

Congratulations! You've achieved a ${streakLength}-day practice streak!

Achievement level: ${achievementLevel.charAt(0).toUpperCase() + achievementLevel.slice(1)}
Reward: ${celebrationType.charAt(0).toUpperCase() + celebrationType.slice(1)}

Consistency is the key to mastery. You're proving you have what it takes to become a great artist!

Keep the streak alive: https://art-buddy-frontend.onrender.com

The Art Buddy Team`;

} else {
  // USER_INACTIVE
  const inactivityDays = body.data?.inactivity_days || 0;
  const engagementLevel = body.data?.engagement_level || 'moderate';

  emailSubject = `🎨 We miss you, ${userName}! Your art journey awaits`;
  emailBody = `Hi ${userName},

It's been ${inactivityDays} day${inactivityDays !== 1 ? 's' : ''} since your last Art Buddy session — we miss you!

Your creative skills are waiting to be developed. Even just 10 minutes of practice today can make a big difference.

Why not try:
  • A quick drawing exercise
  • Reviewing a previous lesson
  • Exploring a new technique

Resume your art journey: https://art-buddy-frontend.onrender.com

We're rooting for you!
The Art Buddy Team`;
}

return [{
  json: {
    user_email: userEmail,
    user_name: userName,
    emailSubject,
    emailBody
  }
}];
